51	// get tokenizer info from model config
52	inline std::optional<TokenizerInfo> GetTokenizerInfo(const tvm::ffi::json::Object& model_config) {
53	  if (model_config.count("tokenizer_info") == 0) {
54	    LOG(WARNING) << "Tokenizer info not found in mlc-chat-config.json. "
55	                 << "Trying to automatically detect the tokenizer info";
56	    return std::nullopt;
57	  }
58	  const tvm::ffi::json::Object& tokenizer_info_obj =
59	      model_config.at("tokenizer_info").cast<tvm::ffi::json::Object>();
60	  auto info = tvm::ffi::make_object<TokenizerInfoNode>();
61	  if (tokenizer_info_obj.count("token_postproc_method")) {
62	    info->token_postproc_method =
63	        tokenizer_info_obj.at("token_postproc_method").cast<std::string>();
64	  }
65	  if (tokenizer_info_obj.count("prepend_space_in_encode")) {
66	    info->prepend_space_in_encode = tokenizer_info_obj.at("prepend_space_in_encode").cast<bool>();
67	  }
68	  if (tokenizer_info_obj.count("strip_space_in_decode")) {
69	    info->strip_space_in_decode = tokenizer_info_obj.at("strip_space_in_decode").cast<bool>();
70	  }
71	  return TokenizerInfo(info);
72	}
