74	inline std::pair<std::optional<std::string>, int> GetEnvSocketHostPort() {
75	  char* host_str = std::getenv("MLC_SOCKET_HOST");
76	  char* port_str = std::getenv("MLC_SOCKET_PORT");
77	  if (host_str == nullptr || port_str == nullptr) {
78	    return {std::nullopt, -1};
79	  }
80	  std::string host(host_str);
81	  if (host.empty()) {
82	    return {std::nullopt, -1};
83	  }
84	  return {host, std::atoi(port_str)};
85	}
