151	/*!
152	 *  \brief This a mock engine that always echo back the inputs
153	 *   and attaches the generation config to usage.extra
154	 *
155	 * \note: mock engine test cannot replace real engine test.
156	 *
157	 * It only tests that parameters are converted and
158	 * passed correctly to the backend.
159	 */
160	class MockEchoEngineImpl : public Engine {
161	 public:
162	  static Result<EngineCreationOutput> Create(const std::string& engine_config_json_str,
163	                                             FRequestStreamCallback request_stream_callback,
164	                                             const tvm::ffi::json::Object& model_config) {
165	    using TResult = Result<EngineCreationOutput>;
166	    // set dummy values
167	    InferrableEngineConfig inferrable_config;
168	    inferrable_config.max_num_sequence = 32;
169	    inferrable_config.max_total_sequence_length = 32 * 4096;
170	    inferrable_config.max_single_sequence_length = 4096;
171	    inferrable_config.prefill_chunk_size = 1024;
172	    inferrable_config.max_history_size = 1024;
173	    tvm::ffi::String err;
174	    auto config_json = tvm::ffi::json::Parse(engine_config_json_str, &err);
175	    if (!err.empty()) {
176	      return TResult::Error(err);
177	    }
178	    EngineConfig engine_config = EngineConfig::FromJSONAndInferredConfig(
179	        config_json.cast<tvm::ffi::json::Object>(), inferrable_config);
180	
181	    auto n = std::make_unique<MockEchoEngineImpl>();
182	    n->request_stream_callback_ = request_stream_callback;
183	    n->tokenizer_ = Tokenizer::FromPath(engine_config->model, GetTokenizerInfo(model_config));
184	    // - Get the default generation config from the first model.
185	    GenerationConfig default_generation_cfg =
186	        GenerationConfig::GetDefaultFromModelConfig(model_config);
187	    return TResult::Ok({std::move(n), std::move(engine_config), std::move(default_generation_cfg)});
188	  }
189	
190	  void Reset() final {}
191	
192	  bool Empty() final { return request_map_.empty(); }
193	
194	  void SetRequestStreamCallback(FRequestStreamCallback request_stream_callback) final {
195	    request_stream_callback_ = request_stream_callback;
196	  }
197	
198	  FRequestStreamCallback GetRequestStreamCallback() final { return request_stream_callback_; }
199	
200	  void AddRequest(Request request) final {
201	    // precompute the stream back results and store them in the request_map
202	    request = Request::FromUntokenized(request, tokenizer_);
203	    std::vector<RequestStreamOutput> outputs;
204	    int64_t completion_tokens = 0;
205	    int64_t prompt_tokens = 0;
206	
207	    for (Data input : request->inputs) {
208	      // only stream back token data
209	      if (auto* token_data = input.as<TokenDataNode>()) {
210	        for (int64_t token_id : token_data->token_ids) {
211	          prompt_tokens += 1;
212	          completion_tokens += 1;
213	          if (request->generation_cfg->max_tokens == -1 ||
214	              completion_tokens <= request->generation_cfg->max_tokens) {
215	            outputs.push_back(RequestStreamOutput(
216	                request->id,
217	                std::vector<std::vector<int64_t>>(request->generation_cfg->n, {token_id}),
218	                std::nullopt,
219	                std::vector<Optional<String>>(request->generation_cfg->n, std::nullopt),
220	                std::vector<String>(request->generation_cfg->n)));
221	          }
222	        }
223	      }
224	    }
225	
226	    // output go beyond max tokens
227	    String finish_reason = "stop";
228	    if (request->generation_cfg->max_tokens != -1 &&
229	        prompt_tokens > request->generation_cfg->max_tokens) {
230	      finish_reason = "length";
231	    }
232	    std::vector<std::vector<int64_t>> group_delta_token_ids;
233	
234	    // correct the last output with right finish reason
235	    if (outputs.size() > 0) {
236	      group_delta_token_ids = outputs.back()->group_delta_token_ids;
237	      outputs.pop_back();
238	    }
239	    outputs.push_back(RequestStreamOutput(
240	        request->id, group_delta_token_ids, std::nullopt,
241	        std::vector<Optional<String>>(request->generation_cfg->n, finish_reason),
242	        std::vector<String>(request->generation_cfg->n)));
243	
244	    // attach usage and config
245	    tvm::ffi::json::Object usage;
246	    usage.Set("prompt_tokens", static_cast<int64_t>(prompt_tokens));
247	    usage.Set("completion_tokens",
248	              static_cast<int64_t>(completion_tokens * request->generation_cfg->n));
249	    usage.Set("total_tokens",
250	              static_cast<int64_t>(prompt_tokens + completion_tokens * request->generation_cfg->n));
251	    usage.Set("extra", request->generation_cfg->AsJSON());
252	    // NOTE: Invariant requirement
253	    // always stream back final usage
254	    // otherwise frontend may have issues deciding termination
255	    outputs.push_back(RequestStreamOutput::Usage(request->id, tvm::ffi::json::Stringify(usage)));
256	    // reverse the stream back so we can just pop back and get out
257	    std::reverse(outputs.begin(), outputs.end());
258	
259	    request_map_[request->id] = MockRequestState{request, std::move(outputs)};
260	  }
261	
262	  void AbortRequest(const String& request_id) {
263	    auto it = request_map_.find(request_id);
264	    if (it == request_map_.end()) return;
265	    Request request = it->second.request;
266	
267	    // If the request input length exceeds the maximum allowed single sequence length,
268	    // invoke callback and do not process the request.
269	    Array<RequestStreamOutput> output{RequestStreamOutput(
270	        request_id, std::vector<std::vector<int64_t>>(request->generation_cfg->n), std::nullopt,
271	        std::vector<Optional<String>>(request->generation_cfg->n, String("abort")),
272	        std::vector<String>(request->generation_cfg->n))};
273	    // NOTE: Invariant requirement
274	    // always stream back final usage
275	    // otherwise frontend may have issues deciding
276	    String dummy_usage =
277	        ("{ \"prompt_tokens\": 0, \"completion_tokens\": 0, \"total_tokens\": 0 }");
278	    output.push_back(RequestStreamOutput::Usage(request->id, dummy_usage));
279	    request_map_.erase(it);
280	    if (request_stream_callback_ != nullptr) {
281	      request_stream_callback_(output);
282	    }
283	  }
284	
285	  void AbortAllRequests() final {
286	    // avoid deletion during iteraton
287	    std::vector<String> request_ids;
288	    for (const auto& kv : request_map_) {
289	      request_ids.push_back(kv.first);
290	    }
291	    for (String req_id : request_ids) {
292	      AbortRequest(req_id);
293	    }
294	  }
295	
296	  void Step() final {
297	    Array<RequestStreamOutput> outputs;
298	    std::vector<String> finished_request_ids;
299	    for (auto& kv : request_map_) {
300	      MockRequestState& state = kv.second;
301	      TVM_FFI_ICHECK_GE(state.reversed_outputs.size(), 2);
302	      if (state.reversed_outputs.size() == 2) {
303	        outputs.push_back(state.reversed_outputs.back());
304	        state.reversed_outputs.pop_back();
305	        outputs.push_back(state.reversed_outputs.back());
306	        finished_request_ids.push_back(kv.first);
307	      } else {
308	        outputs.push_back(state.reversed_outputs.back());
309	        state.reversed_outputs.pop_back();
310	      }
311	    }
312	    for (String req_id : finished_request_ids) {
313	      request_map_.erase(req_id);
314	    }
315	    if (request_stream_callback_ != nullptr) {
316	      request_stream_callback_(outputs);
317	    }
318	  }
319	
320	  /************** Debug/Profile **************/
321	
322	  /*! \brief Internal engine metrics. */
323	  String JSONMetrics() final { return "{}"; }
324	
325	  /*! \brief Call the given global function on all workers. Only for debug purpose. */
326	  void DebugCallFuncOnAllAllWorker(const String& func_name, Optional<String> func_args) final {}
327	
328	 private:
329	  struct MockRequestState {
330	    Request request;
331	    std::vector<RequestStreamOutput> reversed_outputs;
332	  };
333	
334	  // internal tokenizer
335	  // keep for future usage, in case we want to echo back the tokens
336	  Tokenizer tokenizer_;
337	  // callback stream
338	  FRequestStreamCallback request_stream_callback_;
339	  // active requests
340	  std::unordered_map<String, MockRequestState> request_map_;
341	};
