343	/********************** Engine Impl **********************/
344	
345	/*! \brief The implementation of Engine. */
346	class EngineImpl : public Engine {
347	  friend class EngineModule;
348	
349	 public:
350	  /********************** Engine Management **********************/
351	
352	  static Result<EngineCreationOutput> Create(const std::string& engine_config_json_str,
353	                                             DLDevice device,
354	                                             FRequestStreamCallback request_stream_callback,
355	                                             Optional<EventTraceRecorder> trace_recorder) {
356	    using TResult = Result<EngineCreationOutput>;
357	    std::unique_ptr<EngineImpl> n = std::make_unique<EngineImpl>();
358	
359	    // - Read the models and model libs from the EngineConfig JSON string.
360	    Result<std::vector<std::pair<std::string, std::string>>> models_and_model_libs_res =
361	        EngineConfig::GetModelsAndModelLibsFromJSONString(engine_config_json_str);
362	    if (models_and_model_libs_res.IsErr()) {
363	      return TResult::Error(models_and_model_libs_res.UnwrapErr());
364	    }
365	    std::vector<std::pair<std::string, std::string>> models_and_model_libs =
366	        models_and_model_libs_res.Unwrap();
367	
368	    int num_model = models_and_model_libs.size();
369	    TVM_FFI_ICHECK_GE(num_model, 1);
370	    // - Initialize singleton states inside the engine.
371	    n->estate_->Reset();
372	    n->estate_->request_stream_callback_ = std::move(request_stream_callback);
373	    n->trace_recorder_ = trace_recorder;
374	    n->device_ = device;
375	    // - Load model config, create a shared disco session when tensor
376	    // parallelism is enabled.
377	    std::vector<std::string> model_libs;
378	    std::vector<tvm::ffi::json::Object> model_configs;
379	    model_libs.reserve(num_model);
380	    model_configs.reserve(num_model);
381	    for (int i = 0; i < num_model; ++i) {
382	      const auto& [model_str, model_lib] = models_and_model_libs[i];
383	      Result<tvm::ffi::json::Object> model_config_res = Model::LoadModelConfig(model_str);
384	      if (model_config_res.IsErr()) {
385	        return TResult::Error("Model " + std::to_string(i) +
386	                              " has invalid mlc-chat-config.json: " + model_config_res.UnwrapErr());
387	      }
388	      model_libs.push_back(model_lib);
389	      model_configs.push_back(model_config_res.Unwrap());
390	    }
391	
392	    // kick in mock path so we don't have to load in models
393	    if (models_and_model_libs[0].second == "mock://echo") {
394	      return MockEchoEngineImpl::Create(engine_config_json_str,
395	                                        n->estate_->request_stream_callback_, model_configs[0]);
396	    }
397	
398	    auto [session, num_shards, model_num_pipeline_stages] =
399	        n->CreateDiscoSession(model_libs, model_configs, device);
400	
401	    // - Initialize each model independently.
402	    n->models_.clear();
403	    for (int i = 0; i < num_model; ++i) {
404	      const auto& [model_str, model_lib] = models_and_model_libs[i];
405	      Model model = Model::Create(model_lib, model_str, model_configs[i], device, session,
406	                                  num_shards, model_num_pipeline_stages[i],
407	                                  /*trace_enabled=*/trace_recorder.has_value());
408	      n->models_.push_back(model);
409	    }
410	    // - Initialize NVSHMEM
411	    n->estate_->disaggregation = n->models_[0]->GetMetadata().disaggregation;
412	    if (n->estate_->disaggregation) {
413	      LOG(INFO) << "Initializing NVSHMEM";
414	      char* nvshmem_init_config_json_char = std::getenv("MLC_NVSHMEM_INIT_CONFIG_JSON_STR");
415	      TVM_FFI_ICHECK(nvshmem_init_config_json_char != nullptr)
416	          << "The environment variables MLC_NVSHMEM_INIT_CONFIG_JSON_STR should be set.";
417	      std::string f_name = "runtime.disco.nvshmem.init_nvshmem_wrapper";
418	      if (session != nullptr) {
419	        n->DebugCallFuncOnAllAllWorker(f_name, String(nvshmem_init_config_json_char));
420	      } else {
421	        static Function func = Function::GetGlobalRequired(f_name);
422	        func(String(nvshmem_init_config_json_char));
423	      }
424	      LOG(INFO) << "NVSHMEM initialized successfully.";
425	    }
426	
427	    // - Automatically infer the missing fields in EngineConfig JSON strings
428	    // and get the final EngineConfig.
429	    Result<EngineConfig> engine_config_res =
430	        n->AutoDecideEngineConfig(engine_config_json_str, model_configs);
431	    if (engine_config_res.IsErr()) {
432	      return TResult::Error(engine_config_res.UnwrapErr());
433	    }
434	    EngineConfig engine_config = engine_config_res.Unwrap();
435	    {
436	      if (engine_config->prefix_cache_mode == PrefixCacheMode::kRadix) {
437	        n->estate_->prefix_cache = PrefixCache::CreateRadixPrefixCache(
438	            static_cast<size_t>(engine_config->prefix_cache_max_num_recycling_seqs),
439	            [engine_ptr = n.get()](int64_t seq_id) {
440	              RemoveRequestFromModel(engine_ptr->estate_, seq_id, engine_ptr->models_);
441	              engine_ptr->estate_->id_manager.RecycleId(seq_id);
442	            });
443	      } else if (engine_config->prefix_cache_mode == PrefixCacheMode::kDisable) {
444	        n->estate_->prefix_cache = PrefixCache::CreateNoPrefixCache();
445	      } else {
446	        LOG(FATAL) << "Unsupported prefix cache mode: "
447	                   << static_cast<int>(engine_config->prefix_cache_mode);
448	      }
449	      if (engine_config->speculative_mode != SpeculativeMode::kDisable &&
450	          engine_config->prefill_mode == PrefillMode::kHybrid) {
451	        engine_config->prefill_mode = PrefillMode::kChunked;
452	        LOG(WARNING)
453	            << "Hybrid prefill mode fallbacks to chunked prefill, due to speculative mode is "
454	               "enabled and not implemented with hybrid prefill yet.";
455	      }
456	    }
457	    // - Load model weights, create KV cache and workspace.
458	    n->model_workspaces_.clear();
459	    for (const Model& model : n->models_) {
460	      model->LoadParams();
461	      model->SetMaxNumSequence(engine_config->max_num_sequence);
462	      model->SetPrefillChunkSize(engine_config->prefill_chunk_size);
463	      model->CreateKVCache(engine_config->kv_cache_page_size, engine_config->max_num_sequence,
464	                           engine_config->max_total_sequence_length,
465	                           engine_config->prefill_chunk_size, engine_config->max_history_size,
466	                           engine_config->prefix_cache_max_num_recycling_seqs);
467	      n->model_workspaces_.push_back(
468	          ModelWorkspace{model->AllocEmbeddingTensor(), model->AllocHiddenStatesTensor()});
469	    }
470	    // - Initialize tokenizer and grammar
471	    n->tokenizer_ = Tokenizer::FromPath(engine_config->model, GetTokenizerInfo(model_configs[0]));
472	    n->token_table_ = n->tokenizer_->PostProcessedTokenTable();
473	    n->cached_grammar_compiler_ = xgrammar::CachedGrammarCompiler(n->token_table_);
474	    // - Create the logit processor and sampler, and
475	    // the DraftTokenWorkspaceManager for speculative decoding.
476	    int max_num_tokens = engine_config->max_num_sequence;
477	    DraftTokenWorkspaceManager draft_token_workspace_manager{nullptr};
478	    if (engine_config->speculative_mode != SpeculativeMode::kDisable) {
479	      // multiply max num_tokens by two so we can do ping-pong swaping during draft/verify process
480	      draft_token_workspace_manager =
481	          n->models_[0]->CreateDraftTokenWorkspaceManager(max_num_tokens * 2);
482	      draft_token_workspace_manager->AllocWorkspace(
483	          &n->model_workspaces_[0],
484	          /*require_hidden_states=*/engine_config->speculative_mode == SpeculativeMode::kEagle);
485	    }
486	    LogitProcessor logit_processor =
487	        n->models_[0]->CreateLogitProcessor(max_num_tokens, trace_recorder);
488	    Sampler sampler = n->models_[0]->CreateSampler(
489	        max_num_tokens, static_cast<int>(n->models_.size()), trace_recorder);
490	    // - Initialize engine actions that represent state transitions.
491	    if (engine_config->speculative_mode != SpeculativeMode::kDisable) {
492	      n->estate_->spec_draft_length = engine_config->spec_draft_length;
493	    }
494	    n->actions_ =
495	        CreateEngineActions(n->models_, engine_config, model_configs, n->model_workspaces_,
496	                            logit_processor, sampler, draft_token_workspace_manager, n->tokenizer_,
497	                            n->trace_recorder_, n->estate_->request_stream_callback_, device);
498	    n->draft_token_workspace_manager_ = draft_token_workspace_manager;
499	    // - Automatically set the threading backend max concurrency.
500	    n->engine_config_ = engine_config;
501	    n->SetThreadMaxConcurrency();
502	    // - Get the default generation config from the first model.
503	    GenerationConfig default_generation_cfg =
504	        GenerationConfig::GetDefaultFromModelConfig(model_configs[0]);
505	    return TResult::Ok({std::move(n), std::move(engine_config), std::move(default_generation_cfg)});
506	  }
507	
508	  void Reset() final {
509	    AbortAllRequests();
510	    estate_->Reset();
511	    for (Model model : models_) {
512	      model->Reset();
513	    }
514	  }
515	
516	  bool Empty() final { return estate_->running_queue.empty() && estate_->waiting_queue.empty(); }
517	
