549	  /*!
550	   * \brief Handle the given disaggregation request.
551	   * Return true if skipping the subsequent AddRequest process.
552	   */
553	  bool HandleDisaggRequest(Request request) {
554	    DisaggConfig disagg_config = request->generation_cfg->debug_config.disagg_config;
555	    DisaggRequestKind kind = disagg_config.kind;
556	    if (kind == DisaggRequestKind::kPrepareReceive) {
557	      // No-op.
558	      return false;
559	    } else if (kind == DisaggRequestKind::kRemoteSend) {
560	      int input_length = 0;
561	      for (Data input : request->inputs) {
562	        input_length += input->GetLength();
563	      }
564	      // - Truncate the inputs to the desired prefill length (specified by "end").
565	      int kv_window_begin = disagg_config.kv_window_begin.value_or(0);
566	      int kv_window_end = disagg_config.kv_window_end.value_or(input_length);
567	      TVM_FFI_ICHECK_GE(kv_window_begin, 0);
568	      if (kv_window_end < 0) {
569	        kv_window_end = input_length + kv_window_end;
570	      }
571	      TVM_FFI_ICHECK_LT(kv_window_end, input_length)
572	          << "Prefill the full input on the remote machine is not supported.";
573	      TVM_FFI_ICHECK_LT(kv_window_begin, kv_window_end)
574	          << "\"begin >= end\" is not supported by remote prefill";
575	      request->inputs = SplitData(request->inputs, input_length, kv_window_end).first;
576	      // - Check the invariant: "end - begin" equals the expanded metadata length.
577	      TVM_FFI_ICHECK_EQ(disagg_config.kv_append_metadata.size(), models_.size());
578	      for (const Shape& compressed_kv_append_metadata : disagg_config.kv_append_metadata) {
579	        TVM_FFI_ICHECK(!compressed_kv_append_metadata.empty());
580	        int num_segments = compressed_kv_append_metadata[0];
581	        TVM_FFI_ICHECK_EQ(compressed_kv_append_metadata.size(), num_segments * 2 + 1);
582	        int transmission_length = 0;
583	        for (int i = 0; i < num_segments; ++i) {
584	          transmission_length += compressed_kv_append_metadata[i * 2 + 2];
585	        }
586	        TVM_FFI_ICHECK_EQ(transmission_length, kv_window_end - kv_window_begin);
587	      }
588	      // - Override the "n" in generation config to 1.
589	      ObjectPtr<GenerationConfigNode> updated_generation_cfg =
590	          tvm::ffi::make_object<GenerationConfigNode>(*request->generation_cfg.get());
591	      updated_generation_cfg->n = 1;
592	      request->generation_cfg = GenerationConfig(updated_generation_cfg);
593	      return false;
594	    } else if (kind == DisaggRequestKind::kStartGeneration) {
595	      auto it_rstate = estate_->request_states.find(request->id);
596	      TVM_FFI_ICHECK(it_rstate != estate_->request_states.end());
597	      TVM_FFI_ICHECK(!it_rstate->second->entries.empty());
598	      request = it_rstate->second->entries[0]->request;
599	      TVM_FFI_ICHECK(request->generation_cfg->debug_config.disagg_config.kind ==
600	                     DisaggRequestKind::kPrepareReceive);
601	      int input_length = 0;
602	      for (Data input : request->inputs) {
603	        input_length += input->GetLength();
604	      }
605	      // - Truncate the inputs to the desired prefill length (specified by "end").
606	      int kv_window_begin = disagg_config.kv_window_begin.value_or(0);
607	      int kv_window_end = disagg_config.kv_window_end.value_or(input_length);
608	      TVM_FFI_ICHECK_EQ(kv_window_end, input_length);
609	      if (kv_window_begin < 0) {
610	        kv_window_begin = input_length + kv_window_begin;
611	      }
612	      TVM_FFI_ICHECK_GE(kv_window_begin, 0);
613	      TVM_FFI_ICHECK_LT(kv_window_begin, input_length);
614	      // The request is not supposed to be in running queue nor waiting queue.
615	      auto it_running =
616	          std::find(estate_->running_queue.begin(), estate_->running_queue.end(), request);
617	      auto it_waiting =
618	          std::find(estate_->waiting_queue.begin(), estate_->waiting_queue.end(), request);
619	      TVM_FFI_ICHECK(it_running == estate_->running_queue.end());
620	      TVM_FFI_ICHECK(it_waiting == estate_->waiting_queue.end());
621	
622	      RequestState rstate = it_rstate->second;
623	      ObjectPtr<GenerationConfigNode> updated_generation_cfg =
624	          tvm::ffi::make_object<GenerationConfigNode>(*request->generation_cfg.get());
625	      // - Split the input data into two parts at the position "kv_window_begin".
626	      TVM_FFI_ICHECK(!request->inputs.empty());
627	      auto [lhs_data, rhs_data] = SplitData(request->inputs, input_length, kv_window_begin);
628	      if (input_length - kv_window_begin == 1 && request->generation_cfg->n == 1) {
629	        // - Commit the last token id to the request states.
630	        TVM_FFI_ICHECK_EQ(rhs_data.size(), 1);
631	        const auto* token_data = rhs_data.back().as<TokenDataNode>();
632	        TVM_FFI_ICHECK(token_data != nullptr);
633	        TVM_FFI_ICHECK_EQ(token_data->GetLength(), 1);
634	        SampleResult last_token;
635	        last_token.sampled_token_id = {token_data->token_ids.back(), 1.0};
636	        for (RequestModelState mstate : rstate->entries[0]->mstates) {
637	          mstate->CommitToken(last_token);
638	          TVM_FFI_ICHECK_EQ(mstate->committed_tokens.size(), 1);
639	        }
640	        // - Set "next_callback_token_pos" so that this token will not be streamed back to user.
641	        rstate->entries[0]->next_callback_token_pos = 1;
642	        // - Update the request input.
643	        request->inputs = lhs_data;
644	        // - Increment the max_tokens in generation config.
645	        if (request->generation_cfg->max_tokens != -1) {
646	          ++updated_generation_cfg->max_tokens;
647	        }
648	      } else {
649	        // Since there are multiple tokens to prefill, we add the remaining inputs
650	        // to the request's RequestModelStates for prefill.
651	        for (RequestModelState mstate : rstate->entries[0]->mstates) {
652	          mstate->inputs = rhs_data;
653	        }
654	        // Add to waiting queue for prefill.
655	        estate_->waiting_queue.insert(estate_->waiting_queue.begin(), request);
656	      }
657	      estate_->running_queue.push_back(request);
658	      // Erase the disaggregation request kind.
659	      updated_generation_cfg->debug_config.disagg_config.kind = DisaggRequestKind::kNone;
660	      request->generation_cfg = GenerationConfig(updated_generation_cfg);
661	      estate_->running_rsentries_changed = true;
662	      return true;
663	    }
664	    LOG(FATAL) << "Cannot reach here";
665	    throw;
666	  }
