749	  void Step() final {
750	    TVM_FFI_ICHECK(estate_->request_stream_callback_ != nullptr)
751	        << "The request stream callback is not set. Engine cannot execute.";
752	    for (EngineAction action : actions_) {
753	      Array<Request> processed_requests;
754	      {
755	        NVTXScopedRange nvtx_scope("Action step");
756	        processed_requests = action->Step(estate_);
757	      }
758	      if (!processed_requests.empty()) {
759	        ActionStepPostProcess(processed_requests, estate_, models_, tokenizer_,
760	                              estate_->request_stream_callback_,
761	                              engine_config_->max_single_sequence_length,
762	                              draft_token_workspace_manager_, trace_recorder_);
763	        return;
764	      }
765	    }
766	    TVM_FFI_ICHECK(estate_->running_queue.empty())
767	        << "Internal assumption violated: It is expected that an engine step takes at least one "
768	           "action (e.g. prefill, decode, etc.) but it does not.";
769	  }
