893	  Result<EngineConfig> AutoDecideEngineConfig(
894	      const std::string& engine_config_json_str,
895	      const std::vector<tvm::ffi::json::Object>& model_configs) {
896	    using TResult = Result<EngineConfig>;
897	    tvm::ffi::String err;
898	    auto config_json = tvm::ffi::json::Parse(engine_config_json_str, &err);
899	    if (!err.empty()) {
900	      return TResult::Error(err);
901	    }
902	    tvm::ffi::json::Object config = config_json.cast<tvm::ffi::json::Object>();
903	    ObjectPtr<EngineConfigNode> n = tvm::ffi::make_object<EngineConfigNode>();
904	
905	    // - Get the engine mode and maximum GPU utilization for inference.
906	    EngineMode mode = EngineModeFromString(json::Lookup<std::string>(config, "mode"));
907	    double gpu_memory_utilization =
908	        json::LookupOrDefault<double>(config, "gpu_memory_utilization", n->gpu_memory_utilization);
909	    bool verbose = json::LookupOrDefault<bool>(config, "verbose", n->verbose);
910	
911	    // - Get the config fields that can be automatically inferred.
912	    std::optional<int64_t> max_num_sequence =
913	        json::LookupOptional<int64_t>(config, "max_num_sequence");
914	    std::optional<int64_t> max_total_sequence_length =
915	        json::LookupOptional<int64_t>(config, "max_total_sequence_length");
916	    std::optional<int64_t> max_single_sequence_length =
917	        json::LookupOptional<int64_t>(config, "max_single_sequence_length");
918	    std::optional<int64_t> prefill_chunk_size =
919	        json::LookupOptional<int64_t>(config, "prefill_chunk_size");
920	    std::optional<int64_t> max_history_size =
921	        json::LookupOptional<int64_t>(config, "max_history_size");
922	    std::optional<std::string> kv_state_kind_str =
923	        json::LookupOptional<std::string>(config, "kv_state_kind");
924	    InferrableEngineConfig inferrable_cfg{max_num_sequence, max_total_sequence_length,
925	                                          max_single_sequence_length, prefill_chunk_size,
926	                                          max_history_size};
927	
928	    // - Get the model metadata.
929	    std::vector<ModelMetadata> model_metadata;
930	    for (const Model& model : models_) {
931	      model_metadata.push_back(model->GetMetadata());
932	    }
933	    // - Select from kv cache or RNN state.
934	    Result<bool> use_kv_cache = ModelsUseKVCache(model_configs);
935	    if (use_kv_cache.IsErr()) {
936	      return TResult::Error(use_kv_cache.UnwrapErr());
937	    }
938	    Result<InferrableEngineConfig> inferrable_cfg_res;
939	    if (use_kv_cache.Unwrap()) {
940	      // - Infer configuration.
941	      inferrable_cfg_res = InferrableEngineConfig::InferForKVCache(
942	          mode, device_, gpu_memory_utilization, model_configs, model_metadata, inferrable_cfg,
943	          verbose);
944	    } else {
945	      // - Infer configuration.
946	      inferrable_cfg_res = InferrableEngineConfig::InferForRNNState(
947	          mode, device_, gpu_memory_utilization, model_configs, model_metadata, inferrable_cfg,
948	          verbose);
949	    }
950	
951	    if (inferrable_cfg_res.IsErr()) {
952	      return TResult::Error(inferrable_cfg_res.UnwrapErr());
953	    }
954	    inferrable_cfg = inferrable_cfg_res.Unwrap();
955	    TVM_FFI_ICHECK(inferrable_cfg.max_num_sequence.has_value());
956	    TVM_FFI_ICHECK(inferrable_cfg.max_total_sequence_length.has_value());
957	    use_kv_cache = ModelsUseKVCache(model_configs);
958	    if (use_kv_cache.Unwrap()) {
959	      TVM_FFI_ICHECK(inferrable_cfg.max_single_sequence_length.has_value());
960	    }
961	    TVM_FFI_ICHECK(inferrable_cfg.prefill_chunk_size.has_value());
962	    TVM_FFI_ICHECK(inferrable_cfg.max_history_size.has_value());
963	    return TResult::Ok(EngineConfig::FromJSONAndInferredConfig(config, inferrable_cfg));
964	  }
