966	  /*! \brief Set the maximum threading backend concurrency. */
967	  void SetThreadMaxConcurrency() {
968	    int host_cpu_usage = 1;
969	    for (Model model : models_) {
970	      host_cpu_usage += model->EstimateHostCPURequirement();
971	    }
972	    if (host_cpu_usage > 1) {
973	      int max_concurrency = tvm::runtime::threading::MaxConcurrency();
974	      tvm::runtime::threading::SetMaxConcurrency(std::min(
975	          std::max(max_concurrency - host_cpu_usage, 1), engine_config_->max_num_sequence));
976	    }
977	  }
