979	  /*! \brief Create a grammar init context according to the response format. If the response format
980	   * is not JSON, return std::nullopt. */
981	  std::optional<xgrammar::CompiledGrammar> GetGrammarFromResponseFormat(
982	      const ResponseFormat& response_format) {
983	    if (response_format.type != "json_object") {
984	      return std::nullopt;
985	    } else if (!response_format.schema) {
986	      return cached_grammar_compiler_.GetCompiledGrammarForJSON();
987	    } else {
988	      return cached_grammar_compiler_.GetCompiledGrammarForJSONSchema(
989	          response_format.schema.value());
990	    }
991	  }
992	
993	  // Engine state, managing requests and request states.
994	  EngineState estate_;
995	  // Configurations and singletons
996	  EngineConfig engine_config_;
997	  // internal tokenizer
998	  Tokenizer tokenizer_;
999	  std::vector<std::string> token_table_;
1000	  // Cached grammar compiler for grammar matching.
1001	  xgrammar::CachedGrammarCompiler cached_grammar_compiler_;
1002	  // Models
1003	  Array<Model> models_;
1004	  // Device that the models run on.
