1008	  // Engine actions.
1009	  Array<EngineAction> actions_;
1010	  // Draft token workspace manager for speculative decoding.
1011	  Optional<DraftTokenWorkspaceManager> draft_token_workspace_manager_;
1012	  // Event trace recorder.
1013	  Optional<EventTraceRecorder> trace_recorder_;
1014	};
1015	
1016	Result<EngineCreationOutput> Engine::Create(const std::string& engine_config_json_str,
1017	                                            Device device,
