16	Array<EngineAction> CreateEngineActions(Array<Model> models, EngineConfig engine_config,
17	                                        std::vector<tvm::ffi::json::Object> model_configs,
18	                                        std::vector<ModelWorkspace> model_workspaces,
19	                                        LogitProcessor logit_processor, Sampler sampler,
20	                                        DraftTokenWorkspaceManager draft_token_workspace_manager,
21	                                        Tokenizer tokenizer,
22	                                        Optional<EventTraceRecorder> trace_recorder,
23	                                        FRequestStreamCallback request_stream_callback,
24	                                        Device device) {
25	  Array<EngineAction> actions;
26	  ModelMetadata model_metadata = models[0]->GetMetadata();
27	  if (engine_config->speculative_mode != SpeculativeMode::kDisable) {
28	    // Speculative decoding is only possible for more than one model.
29	    TVM_FFI_ICHECK_GT(models.size(), 1U);
30	    if (engine_config->speculative_mode == SpeculativeMode::kEagle) {
31	      TVM_FFI_ICHECK_GT(engine_config->spec_draft_length, 0)
32	          << "The automatic spec decoding does not support Eagle mode as of now.";
33	      actions = {EngineAction::EagleNewRequestPrefill(models,                         //
34	                                                      logit_processor,                //
35	                                                      sampler,                        //
36	                                                      model_workspaces,               //
37	                                                      draft_token_workspace_manager,  //
38	                                                      engine_config,                  //
39	                                                      model_configs,                  //
40	                                                      trace_recorder),
41	                 EngineAction::EagleBatchDraft(models, logit_processor, sampler, model_workspaces,
42	                                               draft_token_workspace_manager, engine_config,
43	                                               trace_recorder),
44	                 EngineAction::EagleBatchVerify(models, logit_processor, sampler, model_workspaces,
45	                                                draft_token_workspace_manager, engine_config,
46	                                                trace_recorder)};
47	    } else if (engine_config->speculative_mode == SpeculativeMode::kMedusa) {
48	      TVM_FFI_ICHECK_GT(engine_config->spec_draft_length, 0)
49	          << "The automatic spec decoding does not support Eagle mode as of now.";
50	      actions = {EngineAction::EagleNewRequestPrefill(models,                         //
51	                                                      logit_processor,                //
52	                                                      sampler,                        //
53	                                                      model_workspaces,               //
54	                                                      draft_token_workspace_manager,  //
55	                                                      engine_config,                  //
56	                                                      model_configs,                  //
57	                                                      trace_recorder),
58	                 EngineAction::EagleBatchVerify(models, logit_processor, sampler, model_workspaces,
59	                                                draft_token_workspace_manager, engine_config,
60	                                                trace_recorder)};
61	    } else if (engine_config->spec_draft_length > 0) {
62	      // The "small draft" mode speculative decoding.
63	      // If "engine_config->spec_draft_length" > 0, it means the draft length is
64	      // configured to be a fixed value.
65	      actions = {
66	          EngineAction::NewRequestPrefill(models,            //
67	                                          logit_processor,   //
68	                                          sampler,           //
69	                                          model_workspaces,  //
70	                                          engine_config,     //
71	                                          model_configs,     //
72	                                          trace_recorder),
73	          EngineAction::BatchDraft(models, logit_processor, sampler, model_workspaces,
74	                                   draft_token_workspace_manager, engine_config, trace_recorder),
75	          EngineAction::BatchVerify(models, logit_processor, sampler, model_workspaces,
76	                                    draft_token_workspace_manager, engine_config, trace_recorder)};
77	    } else {
78	      // The "small draft" mode speculative decoding.
79	      // "engine_config->spec_draft_length" being 0 means we want to enable
80	      // automatic speculative decoding, which decides the spec decoding draft length
81	      // automatically.
82	      actions = {EngineAction::NewRequestPrefill(models,            //
83	                                                 logit_processor,   //
84	                                                 sampler,           //
85	                                                 model_workspaces,  //
86	                                                 engine_config,     //
87	                                                 model_configs,     //
88	                                                 trace_recorder),
89	                 EngineAction::AutoSpecDecode(
90	                     /*spec_decode_actions=*/{EngineAction::BatchDraft(
91	                                                  models, logit_processor, sampler,
92	                                                  model_workspaces, draft_token_workspace_manager,
93	                                                  engine_config, trace_recorder),
94	                                              EngineAction::BatchVerify(
95	                                                  models, logit_processor, sampler,
96	                                                  model_workspaces, draft_token_workspace_manager,
97	                                                  engine_config, trace_recorder)},
98	                     /*batch_decode_actions=*/
99	                     {EngineAction::BatchDecode(models, tokenizer, logit_processor, sampler,
100	                                                engine_config, trace_recorder)},
101	                     engine_config)};
102	    }
103	  } else if (model_metadata.disaggregation) {
104	    actions = {EngineAction::NewRequestPrefill(models,            //
105	                                               logit_processor,   //
106	                                               sampler,           //
107	                                               model_workspaces,  //
108	                                               engine_config,     //
109	                                               model_configs,     //
110	                                               trace_recorder),
111	               EngineAction::BatchDecode(models, tokenizer, logit_processor, sampler, engine_config,
112	                                         trace_recorder)};
113	  } else {
114	    // The normal mode.
115	    actions = {EngineAction::NewRequestPrefill(models,            //
116	                                               logit_processor,   //
117	                                               sampler,           //
118	                                               model_workspaces,  //
119	                                               engine_config,     //
120	                                               model_configs,     //
121	                                               trace_recorder),
122	               EngineAction::BatchJumpForward(models, tokenizer, trace_recorder),
123	               EngineAction::BatchDecode(models, tokenizer, logit_processor, sampler, engine_config,
124	                                         trace_recorder)};
125	  }
126	
127	  if (model_metadata.disaggregation) {
128	    // Insert the disaggregation actions.
129	    Array<EngineAction> disaggregation_actions = {
130	        EngineAction::DisaggPrepareReceive(models, engine_config, model_configs, trace_recorder,
131	                                           request_stream_callback),
132	        EngineAction::DisaggRemoteSend(models, model_workspaces, engine_config, model_configs,
133	                                       trace_recorder, request_stream_callback, device)};
134	    actions.insert(actions.begin(), disaggregation_actions.begin(), disaggregation_actions.end());
135	  }
136	  return actions;
137	}
