15	using tvm::support::NVTXScopedRange;
16	
17	/*!
18	 * \brief The action that prefills requests in the `waiting_queue` of
19	 * the engine state.
20	 */
21	class NewRequestPrefillActionObj : public BatchPrefillBaseActionObj {
22	 public:
23	  explicit NewRequestPrefillActionObj(Array<Model> models, LogitProcessor logit_processor,
24	                                      Sampler sampler, std::vector<ModelWorkspace> model_workspaces,
25	                                      EngineConfig engine_config,
26	                                      std::vector<tvm::ffi::json::Object> model_configs,
27	                                      Optional<EventTraceRecorder> trace_recorder)
28	      : BatchPrefillBaseActionObj(std::move(models), std::move(engine_config),
29	                                  std::move(model_configs), std::move(trace_recorder)),
30	        logit_processor_(std::move(logit_processor)),
31	        sampler_(std::move(sampler)),
32	        model_workspaces_(std::move(model_workspaces)) {}
33	
34	  Array<Request> Step(EngineState estate) final {
35	    // - Find the requests in `waiting_queue` that can prefill in this step.
36	    std::vector<PrefillInput> prefill_inputs;
37	    {
38	      NVTXScopedRange nvtx_scope("NewRequestPrefill getting requests");
39	      prefill_inputs = GetRequestStateEntriesToPrefill(estate);
40	      if (prefill_inputs.empty()) {
41	        return {};
42	      }
43	    }
44	
45	    int num_rsentries = prefill_inputs.size();
46	    {
47	      NVTXScopedRange nvtx_scope("NewRequestPrefill matching prefix");
48	      for (int i = 0; i < num_rsentries; ++i) {
49	        MatchPrefixCache(estate, &prefill_inputs[i]);
50	      }
51	    }
52	
53	    auto tstart = std::chrono::high_resolution_clock::now();
54	
55	    // - Update status of request states from pending to alive.
56	    Array<String> request_ids;
57	    std::vector<RequestState> rstates_of_entries;
58	    std::vector<RequestStateStatus> status_before_prefill;
59	    UpdateRequestToAlive(prefill_inputs, estate, &request_ids, &rstates_of_entries,
60	                         &status_before_prefill);
61	
62	    // - Get embedding and run prefill for each model.
63	    std::vector<int> prefill_lengths;
64	    prefill_lengths.resize(/*size=*/num_rsentries, /*value=*/-1);
65	    Tensor logits_for_sample{nullptr};
66	    for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
67	      std::vector<int64_t> request_internal_ids;
68	      request_internal_ids.reserve(num_rsentries);
69	      ObjectRef embeddings = model_workspaces_[model_id].embeddings;
70	      int cum_prefill_length = 0;
71	      bool single_input =
72	          num_rsentries == 1 && prefill_inputs[0].rsentry->mstates[model_id]->inputs.size() == 1;
73	      std::vector<int64_t> cached_token_data;
74	      for (int i = 0; i < num_rsentries; ++i) {
75	        const RequestStateEntry& rsentry = prefill_inputs[i].rsentry;
76	        RequestModelState mstate = rsentry->mstates[model_id];
77	        auto [input_data, input_length] =
78	            ChunkPrefillInputData(mstate, prefill_inputs[i].max_prefill_length);
79	        if (prefill_lengths[i] == -1) {
80	          prefill_lengths[i] = input_length;
81	        } else {
82	          TVM_FFI_ICHECK_EQ(prefill_lengths[i], input_length);
83	        }
84	        mstate->num_prefilled_tokens += input_length;
85	
86	        TVM_FFI_ICHECK(mstate->draft_output_tokens.empty());
87	        TVM_FFI_ICHECK(mstate->draft_token_slots.empty());
88	        if (status_before_prefill[i] == RequestStateStatus::kPending &&
89	            !estate->prefix_cache->HasSequence(mstate->internal_id)) {
90	          // Add the sequence to the model, or fork the sequence from its parent.
91	          // If the sequence is already in prefix cache, it has also been added/forked in the
92	          // KVCache.
93	          if (rsentry->parent_idx == -1) {
94	            models_[model_id]->AddNewSequence(mstate->internal_id);
95	          } else {
96	            models_[model_id]->ForkSequence(
97	                rstates_of_entries[i]->entries[rsentry->parent_idx]->mstates[model_id]->internal_id,
98	                mstate->internal_id);
99	          }
100	          // Enable sliding window for the sequence if it is not a parent.
101	          if (rsentry->child_indices.empty()) {
102	            models_[model_id]->EnableSlidingWindowForSeq(mstate->internal_id);
103	          }
104	        }
105	        request_internal_ids.push_back(mstate->internal_id);
106	        RECORD_EVENT(trace_recorder_, rsentry->request->id, "start embedding");
107	        for (int j = 0; j < static_cast<int>(input_data.size()); ++j) {
108	          if (!model_id && !prefill_inputs[i].is_decode) {
109	            mstate->prefilled_inputs.push_back(input_data[j]);
110	          }
111	          if (const auto* token_data = input_data[j].as<TokenDataNode>()) {
112	            cached_token_data.insert(cached_token_data.end(), token_data->token_ids.begin(),
113	                                     token_data->token_ids.end());
114	          } else {
115	            if (!cached_token_data.empty()) {
116	              embeddings = TokenData(cached_token_data)
117	                               ->GetEmbedding(models_[model_id],
118	                                              /*dst=*/!single_input ? &embeddings : nullptr,
119	                                              /*offset=*/cum_prefill_length);
120	              cum_prefill_length += cached_token_data.size();
121	              cached_token_data.clear();
122	            }
123	            embeddings = input_data[j]->GetEmbedding(models_[model_id],
124	                                                     /*dst=*/!single_input ? &embeddings : nullptr,
125	                                                     /*offset=*/cum_prefill_length);
126	            cum_prefill_length += input_data[j]->GetLength();
127	          }
128	        }
129	        RECORD_EVENT(trace_recorder_, rsentry->request->id, "finish embedding");
130	      }
131	      if (!cached_token_data.empty()) {
132	        embeddings = TokenData(cached_token_data)
133	                         ->GetEmbedding(models_[model_id],
134	                                        /*dst=*/!single_input ? &embeddings : nullptr,
135	                                        /*offset=*/cum_prefill_length);
136	        cum_prefill_length += cached_token_data.size();
137	        cached_token_data.clear();
138	      }
139	
140	      RECORD_EVENT(trace_recorder_, request_ids, "start prefill");
141	      Tensor logits =
142	          models_[model_id]->BatchPrefill(embeddings, request_internal_ids, prefill_lengths);
143	      RECORD_EVENT(trace_recorder_, request_ids, "finish prefill");
144	      TVM_FFI_ICHECK_EQ(logits->ndim, 3);
145	      TVM_FFI_ICHECK_EQ(logits->shape[0], 1);
146	      TVM_FFI_ICHECK_EQ(logits->shape[1], num_rsentries);
147	
148	      if (model_id == 0) {
149	        // We only need to sample for model 0 in prefill.
150	        logits_for_sample = logits;
151	      }
152	    }
153	
154	    // - Update logits.
155	    TVM_FFI_ICHECK(logits_for_sample.defined());
156	    Array<GenerationConfig> generation_cfg;
157	    Array<RequestModelState> mstates_for_logitproc;
158	    generation_cfg.reserve(num_rsentries);
159	    mstates_for_logitproc.reserve(num_rsentries);
160	    for (int i = 0; i < num_rsentries; ++i) {
161	      generation_cfg.push_back(prefill_inputs[i].rsentry->request->generation_cfg);
162	      mstates_for_logitproc.push_back(prefill_inputs[i].rsentry->mstates[0]);
163	    }
164	    logits_for_sample = logits_for_sample.CreateView({num_rsentries, logits_for_sample->shape[2]},
165	                                                     logits_for_sample->dtype);
166	    logit_processor_->InplaceUpdateLogits(logits_for_sample, generation_cfg, mstates_for_logitproc,
167	                                          request_ids);
168	
169	    // - Compute probability distributions.
170	    Tensor probs_on_device =
171	        logit_processor_->ComputeProbsFromLogits(logits_for_sample, generation_cfg, request_ids);
172	
173	    // - Commit the prefix cache changes from previous round of action.
174	    // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
175	    estate->prefix_cache->CommitSequenceExtention();
176	
177	    // - Sample tokens.
178	    //   For rsentries which have children, sample
179	    //   one token for each rstate that is depending.
180	    //   Otherwise, sample a token for the current rstate.
181	    std::vector<int> sample_indices;
182	    std::vector<RequestStateEntry> rsentries_for_sample;
183	    std::vector<RandomGenerator*> rngs;
184	    std::vector<bool> rsentry_activated;
185	    sample_indices.reserve(num_rsentries);
186	    rsentries_for_sample.reserve(num_rsentries);
187	    rngs.reserve(num_rsentries);
188	    rsentry_activated.reserve(num_rsentries);
189	    request_ids.clear();
190	    generation_cfg.clear();
191	    for (int i = 0; i < num_rsentries; ++i) {
192	      const RequestStateEntry& rsentry = prefill_inputs[i].rsentry;
193	      // No sample for rsentries with remaining inputs.
194	      if (!rsentry->mstates[0]->inputs.empty()) {
195	        continue;
196	      }
197	
198	      int remaining_num_child_to_activate = prefill_inputs[i].num_child_to_activate;
199	      for (int child_idx : rsentry->child_indices) {
200	        // If rstates_of_entries[i]->entries[child_idx] has no committed token,
201	        // the prefill of the current rsentry will unblock
202	        // rstates_of_entries[i]->entries[child_idx],
203	        // and thus we want to sample a token for rstates_of_entries[i]->entries[child_idx].
204	        if (rstates_of_entries[i]->entries[child_idx]->status != RequestStateStatus::kPending ||
205	            !rstates_of_entries[i]->entries[child_idx]->mstates[0]->committed_tokens.empty()) {
206	          continue;
207	        }
208	        sample_indices.push_back(i);
209	        rsentries_for_sample.push_back(rstates_of_entries[i]->entries[child_idx]);
210	        request_ids.push_back(rsentry->request->id);
211	        generation_cfg.push_back(rsentry->request->generation_cfg);
212	        rngs.push_back(&rstates_of_entries[i]->entries[child_idx]->rng);
213	
214	        TVM_FFI_ICHECK(rstates_of_entries[i]->entries[child_idx]->status ==
215	                       RequestStateStatus::kPending);
216	        // We only fork the first `num_child_to_activate` children.
217	        // The children not being forked will be forked via later prefills.
218	        // Usually `num_child_to_activate` is the same as the number of children.
219	        // But it can be fewer subject to the KV cache max num sequence limit.
220	        if (remaining_num_child_to_activate == 0) {
221	          rsentry_activated.push_back(false);
222	          continue;
223	        }
224	        rsentry_activated.push_back(true);
225	        --remaining_num_child_to_activate;
226	        rstates_of_entries[i]->entries[child_idx]->status = RequestStateStatus::kAlive;
227	        for (int model_id = 0; model_id < static_cast<int>(models_.size()); ++model_id) {
228	          int64_t child_internal_id =
229	              rstates_of_entries[i]->entries[child_idx]->mstates[model_id]->internal_id;
230	          models_[model_id]->ForkSequence(rsentry->mstates[model_id]->internal_id,
231	                                          child_internal_id);
232	          // Enable sliding window for the child sequence if the child is not a parent.
233	          if (rstates_of_entries[i]->entries[child_idx]->child_indices.empty()) {
234	            models_[model_id]->EnableSlidingWindowForSeq(child_internal_id);
235	          }
236	        }
237	      }
238	      if (rsentry->child_indices.empty()) {
239	        // If rsentry has no child, we sample a token for itself.
240	        sample_indices.push_back(i);
241	        rsentries_for_sample.push_back(rsentry);
242	        request_ids.push_back(rsentry->request->id);
243	        generation_cfg.push_back(rsentry->request->generation_cfg);
244	        rngs.push_back(&rsentry->rng);
245	        rsentry_activated.push_back(true);
246	      }
247	    }
248	    Tensor renormalized_probs = sampler_->BatchRenormalizeProbsByTopP(
249	        probs_on_device, sample_indices, request_ids, generation_cfg);
250	    std::vector<SampleResult> sample_results = sampler_->BatchSampleTokensWithProbAfterTopP(
251	        renormalized_probs, sample_indices, request_ids, generation_cfg, rngs);
252	    TVM_FFI_ICHECK_EQ(sample_results.size(), rsentries_for_sample.size());
253	
254	    // - Update the committed tokens of states.
255	    // - If a request is first-time prefilled, set the prefill finish time.
256	    UpdateRequestStateEntriesWithSampleResults(rsentries_for_sample, rsentry_activated,
257	                                               sample_results);
258	
259	    auto tend = std::chrono::high_resolution_clock::now();
260	    estate->metrics.engine_prefill_time_sum += static_cast<double>((tend - tstart).count()) / 1e9;
261	
262	    std::vector<Request> processed_requests =
263	        RemoveProcessedRequests(prefill_inputs, estate, rstates_of_entries);
264	    estate->running_rsentries_changed = true;
265	    return processed_requests;
266	  }
267	
268	 private:
269	  /*! \brief The logit processor. */
270	  LogitProcessor logit_processor_;
271	  /*! \brief The sampler to sample new tokens. */
272	  Sampler sampler_;
273	  /*! \brief Workspace of each model. */
274	  std::vector<ModelWorkspace> model_workspaces_;
275	
276	  /*!
277	   * \brief Match the request state entry with prefix cache, to skip prefilling common prefix
278	   * tokens. If the request state entry is not added to KVCache yet, this method will add/fork the
279	   * request in the KVCache, depending on the matching result from prefix cache.
280	   * \param estate The engine state.
281	   * \param[in, out] input The prefill input to be matched and updated.
282	   * \return The matched length in prefix cache.
283	   */
284	  int MatchPrefixCache(EngineState estate, PrefillInput* input) final {
285	    RequestStateEntry rsentry = input->rsentry;
286	    if (estate->prefix_cache->Mode() == PrefixCacheMode::kDisable) {
287	      return 0;
288	    }
289	    if (rsentry->parent_idx == -1 && rsentry->status == RequestStateStatus::kPending &&
290	        !estate->prefix_cache->HasSequence(rsentry->mstates[0]->internal_id)) {
291	      std::vector<int32_t> tokens = GetConcatPrefillInputData(rsentry->mstates[0]);
292	      if (tokens.empty()) {
293	        // If the RequestStateEntry is of empty input data, or not fully tokenized, do nothing
294	        // and return.
295	        return 0;
296	      }
297	      PrefixCacheMatchedResult result = estate->prefix_cache->InsertSequence(
298	          rsentry->mstates[0]->internal_id, tokens, models_[0]->GetSlidingWindowSize(),
299	          models_[0]->GetAttentionSinkSize());
300	
301	      if (result.prefilled_offset == 0) {
302	        // Add new sequence
303	        TVM_FFI_ICHECK_EQ(result.forked_seq_id, -1);
304	        TVM_FFI_ICHECK_EQ(result.reused_seq_id, -1);
305	        TVM_FFI_ICHECK_EQ(result.reused_seq_pop_last_tokens, 0);
306	        for (Model model : models_) {
307	          model->AddNewSequence(rsentry->mstates[0]->internal_id);
308	          // Enable sliding window for the sequence if it is not a parent.
309	          if (rsentry->child_indices.empty()) {
310	            model->EnableSlidingWindowForSeq(rsentry->mstates[0]->internal_id);
311	          }
312	        }
313	      } else {
314	        if (result.forked_seq_id != -1) {
315	          TVM_FFI_ICHECK_EQ(result.reused_seq_id, -1);
316	          TVM_FFI_ICHECK_EQ(result.reused_seq_pop_last_tokens, 0);
317	          // Fork from active sequence
318	          for (Model model : models_) {
319	            model->ForkSequence(result.forked_seq_id, rsentry->mstates[0]->internal_id,
320	                                result.prefilled_offset);
321	            // Enable sliding window for the sequence if it is not a parent.
322	            if (rsentry->child_indices.empty()) {
323	              model->EnableSlidingWindowForSeq(rsentry->mstates[0]->internal_id);
324	            }
325	          }
326	        } else {
327	          // Reuse recycling sequence
328	          TVM_FFI_ICHECK_EQ(result.forked_seq_id, -1);
329	          estate->id_manager.RecycleId(rsentry->mstates[0]->internal_id);
330	          for (int i = 0; i < rsentry->mstates.size(); ++i) {
331	            rsentry->mstates[i]->internal_id = result.reused_seq_id;
332	          }
333	          if (result.reused_seq_pop_last_tokens > 0) {
334	            for (Model model : models_) {
335	              model->PopNFromKVCache(rsentry->mstates[0]->internal_id,
336	                                     result.reused_seq_pop_last_tokens);
337	            }
338	          }
339	        }
340	      }
341	      // Pop matched prefix
342	      if (result.prefilled_offset) {
343	        for (int i = 0; i < rsentry->mstates.size(); ++i) {
344	          PopPrefillInputData(rsentry->mstates[i], result.prefilled_offset);
345	        }
346	      }
347	      // Update max prefill length
348	      input->max_prefill_length =
349	          std::min(input->max_prefill_length, rsentry->mstates[0]->GetInputLength());
350	      return result.prefilled_offset;
351	    }
352	    return 0;
353	  }
354	};  // namespace serve
355	
356	EngineAction EngineAction::NewRequestPrefill(Array<Model> models, LogitProcessor logit_processor,
357	                                             Sampler sampler,
358	                                             std::vector<ModelWorkspace> model_workspaces,
359	                                             EngineConfig engine_config,
360	                                             std::vector<tvm::ffi::json::Object> model_configs,
361	                                             Optional<EventTraceRecorder> trace_recorder) {
362	  return EngineAction(tvm::ffi::make_object<NewRequestPrefillActionObj>(
363	      std::move(models), std::move(logit_processor), std::move(sampler),
364	      std::move(model_workspaces), std::move(engine_config), std::move(model_configs),
365	      std::move(trace_recorder)));
366	}
367	
368	}  // namespace serve
369	}  // namespace llm
370	}  // namespace mlc
