21	using tvm::support::NVTXScopedRange;
22	
23	/*!
24	 * \brief The action that runs one-step decode for requests in the
25	 * `running_queue` of engine state. Preempt low-priority requests
26	 * accordingly when it is impossible to decode all the running requests.
27	 * \note The BatchDecode action **does not** take effect for speculative
28	 * decoding scenarios where there are multiple models. For speculative
29	 * decoding in the future, we will use other specific actions.
30	 */
31	class BatchDecodeActionObj : public EngineActionObj {
32	 public:
33	  explicit BatchDecodeActionObj(Array<Model> models, Tokenizer tokenizer,
34	                                LogitProcessor logit_processor, Sampler sampler,
35	                                EngineConfig engine_config,
36	                                Optional<EventTraceRecorder> trace_recorder)
37	      : models_(std::move(models)),
38	        tokenizer_(std::move(tokenizer)),
39	        logit_processor_(std::move(logit_processor)),
40	        sampler_(std::move(sampler)),
41	        engine_config_(std::move(engine_config)),
42	        trace_recorder_(std::move(trace_recorder)) {}
43	
44	  Array<Request> Step(EngineState estate) final {
45	    // - Do not run decode when there is no running request.
46	    if (estate->running_queue.empty()) {
47	      return {};
48	    }
49	
50	    // Preempt request state entries when decode cannot apply.
51	    std::vector<RequestStateEntry> running_rsentries;
52	    {
53	      NVTXScopedRange nvtx_scope("BatchDecode getting requests");
54	      running_rsentries = estate->GetRunningRequestStateEntries();
55	      while (!CanDecode(running_rsentries.size())) {
56	        if (estate->prefix_cache->TryFreeMemory()) continue;
57	        RequestStateEntry preempted =
58	            PreemptLastRunningRequestStateEntry(estate, models_, std::nullopt, trace_recorder_);
59	        if (preempted.same_as(running_rsentries.back())) {
60	          running_rsentries.pop_back();
61	        }
62	      }
63	      while (running_rsentries.size() >
64	             std::min(static_cast<int64_t>(engine_config_->max_num_sequence),
65	                      engine_config_->prefill_chunk_size)) {
66	        running_rsentries.pop_back();
67	      }
68	    }
69	
70	    auto tstart = std::chrono::high_resolution_clock::now();
71	
72	    // NOTE: Right now we only support decode all the running request states at a time.
73	    int num_rsentries = running_rsentries.size();
74	    TVM_FFI_ICHECK_GT(num_rsentries, 0)
75	        << "There should be at least one request state entry that can run decode. "
76	           "Possible failure reason: none of the prefill phase of the running requests is finished";
77	    TVM_FFI_ICHECK_LE(num_rsentries, engine_config_->max_num_sequence)
78	        << "The number of running requests exceeds the max number of sequence in EngineConfig. "
79	           "Possible failure reason: the prefill action allows new sequence in regardless of the "
80	           "max num sequence.";
81	    // Collect
82	    // - the last committed token,
83	    // - the request id,
84	    // - the generation config,
85	    // - the random number generator,
86	    // of each request state entry.
87	    std::vector<int> input_tokens;
88	    std::vector<int> lengths;
89	    Array<String> request_ids;
90	    std::vector<int64_t> request_internal_ids;
91	    Array<RequestModelState> mstates;
92	    Array<GenerationConfig> generation_cfg;
93	    std::vector<RandomGenerator*> rngs;
94	
95	    input_tokens.reserve(num_rsentries);
96	    request_ids.reserve(num_rsentries);
97	    request_internal_ids.reserve(num_rsentries);
98	    mstates.reserve(num_rsentries);
99	    generation_cfg.reserve(num_rsentries);
100	    rngs.reserve(num_rsentries);
101	
102	    {
103	      NVTXScopedRange nvtx_scope("BatchDecode setting batch info");
104	      for (const RequestStateEntry& rsentry : running_rsentries) {
105	        auto mstate = rsentry->mstates[0];
106	        TVM_FFI_ICHECK(mstate->num_tokens_for_next_decode > 0 &&
107	                       mstate->num_tokens_for_next_decode <=
108	                           static_cast<int>(mstate->committed_tokens.size()));
109	
110	        for (auto begin = mstate->committed_tokens.end() - mstate->num_tokens_for_next_decode;
111	             begin != mstate->committed_tokens.end(); ++begin) {
112	          input_tokens.push_back(begin->GetTokenId());
113	        }
114	
115	        lengths.push_back(mstate->num_tokens_for_next_decode);
116	        mstate->num_tokens_for_next_decode = 0;
117	
118	        request_ids.push_back(rsentry->request->id);
119	        request_internal_ids.push_back(mstate->internal_id);
120	        mstates.push_back(mstate);
121	        generation_cfg.push_back(rsentry->request->generation_cfg);
122	        rngs.push_back(&rsentry->rng);
123	      }
124	    }
125	
126	    // - Compute embeddings.
127	    RECORD_EVENT(trace_recorder_, request_ids, "start embedding");
128	    ObjectRef embeddings =
129	        models_[0]->TokenEmbed({Shape(input_tokens.begin(), input_tokens.end())});
130	    RECORD_EVENT(trace_recorder_, request_ids, "finish embedding");
131	
132	    // - Invoke model decode.
133	    // If every request only requires to process one token, batch decode kernel is called.
134	    // Otherwise, batch prefill kernel is called.
135	    bool is_every_request_single_token =
136	        std::all_of(lengths.begin(), lengths.end(), [](int len) { return len == 1; });
137	    RECORD_EVENT(trace_recorder_, request_ids, "start decode");
138	    Tensor logits;
139	    if (is_every_request_single_token) {
140	      logits = models_[0]->BatchDecode(embeddings, request_internal_ids);
141	      TVM_FFI_ICHECK_EQ(logits->ndim, 3);
142	      TVM_FFI_ICHECK_EQ(logits->shape[0], num_rsentries);
143	      TVM_FFI_ICHECK_EQ(logits->shape[1], 1);
144	    } else {
145	      logits = models_[0]->BatchPrefill(embeddings, request_internal_ids, lengths);
146	      TVM_FFI_ICHECK_EQ(logits->ndim, 3);
147	      TVM_FFI_ICHECK_EQ(logits->shape[0], 1);
148	      TVM_FFI_ICHECK_EQ(logits->shape[1], num_rsentries);
149	    }
150	    RECORD_EVENT(trace_recorder_, request_ids, "finish decode");
151	
152	    // - Update logits.
153	    logits = logits.CreateView({num_rsentries, logits->shape[2]}, logits->dtype);
154	    logit_processor_->InplaceUpdateLogits(logits, generation_cfg, mstates, request_ids);
155	
156	    // - Compute probability distributions.
157	    Tensor probs_on_device =
158	        logit_processor_->ComputeProbsFromLogits(logits, generation_cfg, request_ids);
159	
160	    // - Commit the prefix cache changes from previous round of action.
161	    // Note: we commit prefix cache changes here to overlap this commit with the GPU execution.
162	    estate->prefix_cache->CommitSequenceExtention();
163	
164	    // - Sample tokens.
165	    // Fill range [0, num_rsentries) into `sample_indices`.
166	    std::vector<int> sample_indices(num_rsentries);
167	    std::iota(sample_indices.begin(), sample_indices.end(), 0);
168	    Tensor renormalized_probs = sampler_->BatchRenormalizeProbsByTopP(
169	        probs_on_device, sample_indices, request_ids, generation_cfg);
170	    std::vector<SampleResult> sample_results = sampler_->BatchSampleTokensWithProbAfterTopP(
171	        renormalized_probs, sample_indices, request_ids, generation_cfg, rngs);
172	    TVM_FFI_ICHECK_EQ(sample_results.size(), num_rsentries);
173	
174	    // - Update the committed tokens of states.
175	    for (int i = 0; i < num_rsentries; ++i) {
176	      auto mstate = mstates[i];
177	
178	      if (!mstate->require_retokenization_in_next_decode) {
179	        mstates[i]->CommitToken(sample_results[i]);
180	        // live update the output metrics
181	        running_rsentries[i]->rstate->metrics.completion_tokens += 1;
182	      } else {
183	        // Retokenize and commit tokens.
184	        CommitTokenMayRetokenize(running_rsentries[i], mstate, sample_results[i]);
185	        mstate->require_retokenization_in_next_decode = false;
186	      }
187	
188	      running_rsentries[i]->rstate->metrics.decode_tokens += lengths[i];
189	    }
190	
191	    double elapsed_time;
192	    {
193	      NVTXScopedRange nvtx_scope("BatchDecode get time");
194	      auto tend = std::chrono::high_resolution_clock::now();
195	      elapsed_time = static_cast<double>((tend - tstart).count()) / 1e9;
196	    }
197	    estate->metrics.engine_decode_time_sum += elapsed_time;
198	    estate->metrics.UpdateDecodeTimeByBatchSize(num_rsentries, elapsed_time);
199	
200	    return estate->running_queue;
201	  }
202	
203	 private:
204	  /*! \brief Check if the input request state entries can be decoded under conditions. */
205	  bool CanDecode(int num_rsentries) {
206	    int num_available_pages = models_[0]->GetNumAvailablePages();
207	    return num_rsentries <= num_available_pages;
208	  }
209	
210	  /*!
211	   * \brief Retokenize the past tokens with a new token.
212	   * \param mstate The model state.
213	   * \param token_id The new token id.
214	   * \param max_rollback_tokens The maximum number of tokens to rollback.
215	   * \return The number of tokens to rollback and the new tokens.
216	   */
217	  std::pair<int, std::vector<int32_t>> RetokenizeWithNewToken(RequestModelState mstate,
218	                                                              int32_t token_id,
219	                                                              int max_rollback_tokens) {
220	    // Step 1. Get past tokens
221	    // past_tokens = mstate[-max_rollback_tokens:]
222	    // past_string = detokenize(past_tokens)
223	    const auto& token_table = tokenizer_->PostProcessedTokenTable();
224	    std::vector<int32_t> past_tokens;
225	    std::string past_string;
226	    auto past_begin_it = mstate->committed_tokens.size() >= max_rollback_tokens
227	                             ? mstate->committed_tokens.end() - max_rollback_tokens
228	                             : mstate->committed_tokens.begin();
229	    for (auto it = past_begin_it; it != mstate->committed_tokens.end(); ++it) {
230	      past_tokens.push_back(it->GetTokenId());
231	      past_string += token_table[it->GetTokenId()];
232	    }
233	
234	    // Step 2. Retokenize
235	    // Compare tokenize(past_string + new_string) and past_tokens
236	    auto new_tokens = tokenizer_->EncodeNoPrependSpace(past_string + token_table[token_id]);
237	
238	    int first_differ_idx = past_tokens.size();
239	    for (int i = 0; i < static_cast<int>(past_tokens.size()); ++i) {
240	      if (i == static_cast<int>(new_tokens.size()) || past_tokens[i] != new_tokens[i]) {
241	        first_differ_idx = i;
242	        break;
243	      }
244	    }
245	
246	    return {past_tokens.size() - first_differ_idx,
247	            std::vector<int32_t>(new_tokens.begin() + first_differ_idx, new_tokens.end())};
248	  }
249	
250	  /*!
251	   * \brief Commit the token and may retokenize the past tokens.
252	   * \param rsentry The request state entry.
253	   * \param mstate The model state.
254	   * \param sample_result The sampled token.
255	   */
256	  void CommitTokenMayRetokenize(RequestStateEntry rsentry, RequestModelState mstate,
257	                                const SampleResult& sample_result) {
258	    auto generation_cfg = rsentry->request->generation_cfg;
259	    // 1. If EOS token is generated, jump commit it
260	    if (!generation_cfg->debug_config.ignore_eos &&
261	        std::any_of(generation_cfg->stop_token_ids.begin(), generation_cfg->stop_token_ids.end(),
262	                    [&](int32_t token) { return token == sample_result.GetTokenId(); })) {
263	      mstate->CommitToken(sample_result);
264	      rsentry->rstate->metrics.completion_tokens += 1;
265	      return;
266	    }
267	
268	    // 2. Check retokenization
269	    const auto& committed_tokens = mstate->committed_tokens;
270	    auto [rollback_cnt, new_tokens] =
271	        RetokenizeWithNewToken(mstate, sample_result.GetTokenId(), MAX_ROLLBACK_TOKENS_);
272	
273	    // 3. Handle output when retokenization happens
274	    if (rollback_cnt >
